def main():
    n = int(input())
    room = []
    for i in range(n):
        room.append(input())
    print(max_clean_rows(room))


def max_clean_rows(room):
    n = len(room)
    clean_rows = 0
    for i in range(n):
        if room[i] == '1' * n:
            clean_rows += 1
    return clean_rows


if __name__ == '__main__':
    main()
